const EXPECTED_COUNT = 30;

function getExtractedText(item) {
  return (
    item.json.jsonl_raw ||
    item.json.data ||
    item.json.text ||
    item.json.content ||
    ''
  );
}

const accepted = [];
const rejected = [];

for (const item of $input.all()) {
  const raw = getExtractedText(item);

  const lines = String(raw)
    .split(/\r?\n/)
    .map(line => line.trim())
    .filter(Boolean);

  for (const [lineIndex, line] of lines.entries()) {
    let obj;

    try {
      obj = JSON.parse(line);
    } catch (error) {
      rejected.push({
        line: lineIndex + 1,
        reason: 'invalid_json',
        preview: line.slice(0, 200)
      });
      continue;
    }

    const statut =
      obj.statut ||
      obj.statut_document ||
      obj.metadata?.statut ||
      obj.metadata?.statut_document;

    const validation =
      obj.validation ||
      obj.metadata?.validation;

    const content =
      obj.contenu_chunk ||
      obj.content ||
      obj.text ||
      obj.pageContent ||
      '';

    const chunkId =
      obj.chunk_id ||
      obj.metadata?.chunk_id ||
      `pilat_chunk_${String(lineIndex + 1).padStart(4, '0')}`;

    const forbiddenStatuses = new Set([
      'REVIEW',
      'DRAFT',
      'DEPRECATED',
      'ARCHIVED'
    ]);

    if (forbiddenStatuses.has(statut)) {
      rejected.push({
        chunk_id: chunkId,
        statut,
        validation,
        reason: `forbidden_status_${statut}`
      });
      continue;
    }

    if (statut !== 'VALIDATED') {
      rejected.push({
        chunk_id: chunkId,
        statut,
        validation,
        reason: 'not_validated'
      });
      continue;
    }

    if (!content || content.length < 10) {
      rejected.push({
        chunk_id: chunkId,
        statut,
        validation,
        reason: 'empty_or_too_short_content'
      });
      continue;
    }

    accepted.push({
      json: {
        chunk_id: chunkId,
        document_id: obj.document_id || 'pilat_doctrine',
        source_file: obj.source_file || 'pilat_production_candidate_chunks.jsonl',
        document_title: obj.document_title || '',
        section_path: obj.section_path || '',
        version: obj.version || '1.0.0',
        statut_document: statut,
        validation: validation || 'validé_humainement',
        data_status: obj.data_status || 'DOCTRINE',
        territoire: obj.territoire || 'non_specifie',
        date_reference: obj.date_reference || '',
        confidence_level: obj.confidence_level || 'élevé',
        tags: obj.tags || ['pilat', 'validated', 'doctrine'],
        word_count: obj.word_count || null,
        content,
        collection_name: 'pilat_validated_doctrine_v1',
        ingestion_rule: 'validated_human_only',
        index_ready: true
      }
    });
  }
}

if (accepted.length !== EXPECTED_COUNT) {
  throw new Error(
    `HOLD: expected ${EXPECTED_COUNT} validated chunks, got ${accepted.length}. Rejected: ${rejected.length}. Details: ${JSON.stringify(rejected.slice(0, 10))}`
  );
}

return accepted;

const EXPECTED_COUNT = 30;
const REQUIRED_COLLECTION = 'pilat_validated_doctrine_v1';

const items = $input.all();

const summary = {
  total_items: items.length,
  validated: 0,
  human_validated: 0,
  index_ready: 0,
  wrong_collection: 0,
  invalid_items: []
};

for (const [index, item] of items.entries()) {
  const j = item.json;

  const isValidated = j.statut_document === 'VALIDATED';
  const isHumanValidated = j.validation === 'validé_humainement';
  const isIndexReady = j.index_ready === true;
  const isRightCollection = j.collection_name === REQUIRED_COLLECTION;

  if (isValidated) summary.validated++;
  if (isHumanValidated) summary.human_validated++;
  if (isIndexReady) summary.index_ready++;
  if (!isRightCollection) summary.wrong_collection++;

  if (!isValidated || !isHumanValidated || !isIndexReady || !isRightCollection) {
    summary.invalid_items.push({
      index,
      chunk_id: j.chunk_id,
      statut_document: j.statut_document,
      validation: j.validation,
      index_ready: j.index_ready,
      collection_name: j.collection_name
    });
  }
}

if (summary.total_items !== EXPECTED_COUNT) {
  throw new Error(`HOLD: expected ${EXPECTED_COUNT} chunks, got ${summary.total_items}`);
}

if (summary.invalid_items.length > 0) {
  throw new Error(
    `HOLD: invalid chunks detected: ${JSON.stringify(summary.invalid_items.slice(0, 10))}`
  );
}

// Important : on certifie, puis on laisse passer les 30 chunks
return items.map(item => ({
  json: {
    ...item.json,
    qa_decision: 'GO',
    qa_message: 'QA passed — chunk validated for vector ingestion.',
    qa_expected_count: EXPECTED_COUNT,
    qa_total_items: summary.total_items,
    qa_validated: summary.validated,
    qa_human_validated: summary.human_validated,
    qa_index_ready: summary.index_ready
  }
}));
